#include <bits/stdc++.h>
using namespace std;
int check(int a){
	int n=a;
    int sum=0;
    for(int i=2;i*i<=a;i++){
    	if(n%i==0){
    		sum++;
    		//cout<<i<<endl;
    	}
		while(n%i==0 && n>1)n/=i;
        if(sum>2)return 0;
    }
    if(n>1)sum++;
    return sum==2;
}
int main(){
    int n,a;
    cin>>n;
    while(n--){
        cin>>a;
        cout<<check(a)<<endl;
    }
    return 0;
}
